function e(e,t){const n=document.getElementById(e),a=document.getElementById(t);n&&a&&n.addEventListener("submit",e=>{e.preventDefault();const t=new FormData(n),s=String(t.get("email")??"").trim(),o=String(t.get("senha")??"");s&&o?(a.innerHTML='<div class="text-muted">Entrando...</div>',async function(e){const t=await fetch("usuarios/logica/login_usuario.php",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(e)});return await t.json()}({email:s,senha:o}).then(e=>{e.sucesso?(a.innerHTML=`<div class="alert alert-success mb-0">${e.mensagem}</div>`,e.sucesso&&e.usuario&&(window.location.href="home.php")):a.innerHTML=`<div class="alert alert-danger mb-0">${e.mensagem}</div>`}).catch(()=>{a.innerHTML='<div class="alert alert-danger mb-0">Erro inesperado ao comunicar com o servidor.</div>'})):a.innerHTML='<div class="alert alert-warning mb-0">Preencha e-mail e senha.</div>'})}document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll(".toggle-password").forEach(e=>{const t=e.getAttribute("data-target");if(!t)return;const n=document.getElementById(t);n&&e.addEventListener("click",()=>{const t="password"===n.type;n.type=t?"text":"password";const a=e.querySelector("i");a&&(a.classList.toggle("bi-eye",!t),a.classList.toggle("bi-eye-slash",t))})}),e("form-login","resultado-login")});
